            let payload: Value = serde_json::from_str(r#"{"e":"depthUpdate","E":1591269996801,"T":1591269996646,"s":"BTCUSD_200626","ps":"BTCUSD","U":17276694,"u":17276701,"pu":17276678,"b":[["9523.0"]],"a":[["9524.6"]],"st":1}"#).unwrap_or_else(|_| serde_json::json!({}));
